 41→import com.ichi2.anki.snackbar.BaseSnackbarBuilderProvider
 42→import com.ichi2.anki.snackbar.SnackbarBuilder
 43→import com.ichi2.annotations.NeedsTest
 44→import com.ichi2.compat.CompatHelper.Companion.getSerializableCompat
 45→import com.ichi2.utils.performClickIfEnabled
 46→import kotlinx.coroutines.flow.collectLatest
 47→import kotlinx.coroutines.launch
 48→
 49→class PreviewerFragment :
 50→    CardViewerFragment(R.layout.previewer),
 51→    Toolbar.OnMenuItemClickListener,
 52→    BaseSnackbarBuilderProvider,
 53→    DispatchKeyEventListener {
 54→
 55→    override val viewModel: PreviewerViewModel by viewModels {
 56→        val previewerIdsFile = requireNotNull(requireArguments().getSerializableCompat(CARD_IDS_FILE_ARG)) {
 57→            "$CARD_IDS_FILE_ARG is required"
 58→        } as PreviewerIdsFile
 59→        val currentIndex = requireArguments().getInt(CURRENT_INDEX_ARG, 0)
 60→        PreviewerViewModel.factory(previewerIdsFile, currentIndex)
 61→    }
 62→    override val webView: WebView
 63→        get() = requireView().findViewById(R.id.webview)
 64→
 65→    override val baseSnackbarBuilder: SnackbarBuilder
 66→        get() = {
 67→            val slider = this@PreviewerFragment.view?.findViewById<Slider>(R.id.slider)
 68→            anchorView = if (slider?.isVisible == true) {
 69→                slider
 70→            } else {
 71→                this@PreviewerFragment.view?.findViewById<MaterialButton>(R.id.show_next)
 72→            }
 73→        }
 74→
 75→    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
 76→        super.onViewCreated(view, savedInstanceState)
 77→        val slider = view.findViewById<Slider>(R.id.slider)
 78→        val nextButton = view.findViewById<MaterialButton>(R.id.show_next)
 79→        val previousButton = view.findViewById<MaterialButton>(R.id.show_previous)
 80→        val progressIndicator = view.findViewById<MaterialTextView>(R.id.progress_indicator)
 81→        val cardsCount = viewModel.cardsCount()
 82→
 83→        lifecycleScope.launch {
 84→            viewModel.currentIndex
 85→                .flowWithLifecycle(lifecycle)
 86→                .collectLatest { currentIndex ->
 87→                    val displayIndex = currentIndex + 1
 88→                    slider.value = displayIndex.toFloat()
 89→                    progressIndicator.text =
 90→                        getString(R.string.preview_progress_bar_text, displayIndex, cardsCount)
 91→                }
 92→        }
 93→        /* ************************************* Menu items ************************************* */
 94→        val menu = view.findViewById<Toolbar>(R.id.toolbar).menu
 95→
 96→        lifecycleScope.launch {
 97→            viewModel.backSideOnly
 98→                .flowWithLifecycle(lifecycle)
 99→                .collectLatest { isBackSideOnly ->
100→                    setBackSideOnlyButtonIcon(menu, isBackSideOnly)
101→                }
102→        }
103→
104→        lifecycleScope.launch {
105→            viewModel.isMarked
106→                .flowWithLifecycle(lifecycle)
107→                .collectLatest { isMarked ->
108→                    with(menu.findItem(R.id.action_mark)) {
109→                        if (isMarked) {
110→                            setIcon(R.drawable.ic_star)
111→                            setTitle(R.string.menu_unmark_note)
112→                        } else {
113→                            setIcon(R.drawable.ic_star_border_white)
114→                            setTitle(R.string.menu_mark_note)
115→                        }
116→                    }
117→                }
118→        }
119→
120→        lifecycleScope.launch {
121→            viewModel.flagCode
122→                .flowWithLifecycle(lifecycle)
123→                .collectLatest { flagCode ->
124→                    menu.findItem(R.id.action_flag).setIcon(Flag.fromCode(flagCode).drawableRes)
125→                }
126→        }
127→
128→        @NeedsTest("webview don't vanish when only one card is in the list")
129→        if (cardsCount == 1) {
130→            slider.visibility = View.GONE
131→            progressIndicator.visibility = View.GONE
132→        }
133→
134→        slider.apply {
135→            valueTo = cardsCount.toFloat()
136→            addOnSliderTouchListener(
137→                object : Slider.OnSliderTouchListener {
138→                    override fun onStartTrackingTouch(slider: Slider) {}
139→
140→                    override fun onStopTrackingTouch(slider: Slider) {
141→                        viewModel.onSliderChange(slider.value.toInt())
142→                    }
143→                }
144→            )
145→        }
146→
147→        lifecycleScope.launch {
148→            viewModel.isNextButtonEnabled.collectLatest {
149→                nextButton.isEnabled = it
150→            }
151→        }
152→
153→        nextButton.setOnClickListener {
154→            viewModel.onNextButtonClick()
155→        }
156→
157→        lifecycleScope.launch {
158→            viewModel.isBackButtonEnabled.collectLatest {
159→                previousButton.isEnabled = it
160→            }
161→        }
162→
163→        previousButton.setOnClickListener {
164→            viewModel.onPreviousButtonClick()
165→        }
166→
167→        view.findViewById<MaterialToolbar>(R.id.toolbar).apply {
168→            setOnMenuItemClickListener(this@PreviewerFragment)
169→            setNavigationOnClickListener { requireActivity().onBackPressedDispatcher.onBackPressed() }
170→        }
171→    }
172→
173→    override fun onMenuItemClick(item: MenuItem): Boolean {
174→        when (item.itemId) {
175→            R.id.action_edit -> editCard()
176→            R.id.action_mark -> viewModel.toggleMark()
177→            R.id.action_back_side_only -> viewModel.toggleBackSideOnly()
178→            R.id.action_flag_zero -> viewModel.setFlag(Flag.NONE)
179→            R.id.action_flag_one -> viewModel.setFlag(Flag.RED)
180→            R.id.action_flag_two -> viewModel.setFlag(Flag.ORANGE)
181→            R.id.action_flag_three -> viewModel.setFlag(Flag.GREEN)
182→            R.id.action_flag_four -> viewModel.setFlag(Flag.BLUE)
183→            R.id.action_flag_five -> viewModel.setFlag(Flag.PINK)
184→            R.id.action_flag_six -> viewModel.setFlag(Flag.TURQUOISE)
185→            R.id.action_flag_seven -> viewModel.setFlag(Flag.PURPLE)
186→        }
187→        return true
188→    }
189→
190→    private fun setBackSideOnlyButtonIcon(menu: Menu, isBackSideOnly: Boolean) {
191→        menu.findItem(R.id.action_back_side_only).apply {
192→            if (isBackSideOnly) {
193→                setIcon(R.drawable.ic_card_answer)
194→                setTitle(R.string.card_side_answer)
195→            } else {
196→                setIcon(R.drawable.ic_card_question)
197→                setTitle(R.string.card_side_both)
198→            }
199→        }
200→    }
201→
202→    private val editCardLauncher = registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
203→        viewModel.handleEditCardResult(result)
204→    }
205→
206→    private fun editCard() {
207→        val intent = viewModel.getNoteEditorDestination().toIntent(requireContext())
208→        editCardLauncher.launch(intent)
209→    }
210→
211→    override fun dispatchKeyEvent(event: KeyEvent): Boolean {
212→        if (event.action != KeyEvent.ACTION_DOWN) return false
213→
214→        when (event.keyCode) {
215→            KeyEvent.KEYCODE_DPAD_LEFT -> {
216→                requireView().findViewById<MaterialButton>(R.id.show_previous).performClickIfEnabled()
217→            }
218→            KeyEvent.KEYCODE_DPAD_RIGHT -> {
219→                requireView().findViewById<MaterialButton>(R.id.show_next).performClickIfEnabled()
220→            }
221→            KeyEvent.KEYCODE_R -> viewModel.replayAudios()
222→            else -> return false
223→        }
224→        return true
225→    }
226→
227→    companion object {
228→        /** Index of the card to be first displayed among the IDs provided by [CARD_IDS_FILE_ARG] */
229→        const val CURRENT_INDEX_ARG = "currentIndex"
230→
231→        /** Argument key to a [PreviewerIdsFile] with the IDs of the cards to be displayed */
232→        const val CARD_IDS_FILE_ARG = "cardIdsFile"
233→
234→        fun getIntent(context: Context, previewerIdsFile: PreviewerIdsFile, currentIndex: Int): Intent {
235→            val arguments = bundleOf(
236→                CURRENT_INDEX_ARG to currentIndex,
237→                CARD_IDS_FILE_ARG to previewerIdsFile
238→            )
239→            return PreviewerActivity.getIntent(context, PreviewerFragment::class, arguments)
240→        }
241→    }
242→}
